// frontend/src/components/admin/ReportsAnalytics.js
import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import './Admin.css';

const ReportsAnalytics = () => {
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [dateRange, setDateRange] = useState('week');
    const [reportData, setReportData] = useState(null);
    const [exportFormat, setExportFormat] = useState('csv');

    useEffect(() => {
        loadReportData();
    }, [dateRange]);

    const loadReportData = async () => {
        setLoading(true);
        try {
            const response = await api.get(`/admin/reports?range=${dateRange}`);
            if (response.data.success) {
                setReportData(response.data.data);
            }
        } catch (error) {
            console.error('Error loading report data:', error);
            setError('Failed to load report data');
        } finally {
            setLoading(false);
        }
    };

    const handleExport = async () => {
        try {
            const response = await api.get(`/admin/export?format=${exportFormat}&range=${dateRange}`, {
                responseType: 'blob'
            });

            const url = window.URL.createObjectURL(new Blob([response.data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', `report-${dateRange}.${exportFormat}`);
            document.body.appendChild(link);
            link.click();
            link.remove();
        } catch (error) {
            console.error('Error exporting data:', error);
            alert('Failed to export data');
        }
    };

    if (loading) {
        return <div className="loading-spinner">Loading reports...</div>;
    }

    return (
        <div className="reports-tab">
            <div className="management-header">
                <h1>📈 Reports & Analytics</h1>
                <div className="report-actions">
                    <select 
                        value={dateRange} 
                        onChange={(e) => setDateRange(e.target.value)}
                        className="range-select"
                    >
                        <option value="today">Today</option>
                        <option value="week">This Week</option>
                        <option value="month">This Month</option>
                        <option value="quarter">This Quarter</option>
                        <option value="year">This Year</option>
                        <option value="all">All Time</option>
                    </select>

                    <select 
                        value={exportFormat} 
                        onChange={(e) => setExportFormat(e.target.value)}
                        className="format-select"
                    >
                        <option value="csv">CSV</option>
                        <option value="excel">Excel</option>
                        <option value="pdf">PDF</option>
                    </select>

                    <button className="btn-export" onClick={handleExport}>
                        📥 Export Report
                    </button>
                </div>
            </div>

            {error && <div className="error-message">{error}</div>}

            <div className="reports-grid">
                {/* Key Metrics */}
                <div className="report-card">
                    <h3>Key Metrics</h3>
                    <div className="metrics-grid">
                        <div className="metric">
                            <span className="metric-label">New Users</span>
                            <span className="metric-value">{reportData?.newUsers || 0}</span>
                        </div>
                        <div className="metric">
                            <span className="metric-label">New Jobs</span>
                            <span className="metric-value">{reportData?.newJobs || 0}</span>
                        </div>
                        <div className="metric">
                            <span className="metric-label">Completed Jobs</span>
                            <span className="metric-value">{reportData?.completedJobs || 0}</span>
                        </div>
                        <div className="metric">
                            <span className="metric-label">Revenue</span>
                            <span className="metric-value">R{reportData?.revenue?.toLocaleString() || 0}</span>
                        </div>
                    </div>
                </div>

                {/* User Growth */}
                <div className="report-card">
                    <h3>User Growth</h3>
                    <div className="chart-placeholder">
                        <div className="bar-chart">
                            {reportData?.userGrowth?.map((item, index) => (
                                <div key={index} className="chart-bar" style={{ height: `${item.percentage}%` }}>
                                    <span className="bar-label">{item.month}</span>
                                    <span className="bar-value">{item.count}</span>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Job Categories Distribution */}
                <div className="report-card">
                    <h3>Jobs by Category</h3>
                    <div className="pie-chart-placeholder">
                        {reportData?.categories?.map((cat, index) => (
                            <div key={index} className="category-stat">
                                <span className="category-name">{cat.name}</span>
                                <div className="progress-bar">
                                    <div 
                                        className="progress-fill" 
                                        style={{ width: `${cat.percentage}%` }}
                                    ></div>
                                </div>
                                <span className="category-count">{cat.count}</span>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Township Activity */}
                <div className="report-card">
                    <h3>Top Townships</h3>
                    <div className="township-list">
                        {reportData?.topTownships?.map((town, index) => (
                            <div key={index} className="township-item">
                                <span className="township-name">{town.name}</span>
                                <span className="township-count">{town.jobs} jobs</span>
                                <span className="township-percent">{town.percentage}%</span>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Daily Activity */}
                <div className="report-card full-width">
                    <h3>Daily Activity (Last 7 Days)</h3>
                    <div className="activity-chart">
                        <table className="activity-table">
                            <thead>
                                <tr>
                                    <th>Date</th>
                                    <th>New Users</th>
                                    <th>New Jobs</th>
                                    <th>Applications</th>
                                    <th>Completions</th>
                                    <th>Revenue</th>
                                </tr>
                            </thead>
                            <tbody>
                                {reportData?.dailyActivity?.map((day, index) => (
                                    <tr key={index}>
                                        <td>{day.date}</td>
                                        <td>{day.newUsers}</td>
                                        <td>{day.newJobs}</td>
                                        <td>{day.applications}</td>
                                        <td>{day.completions}</td>
                                        <td>R{day.revenue}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ReportsAnalytics;
